module sequential_read_mem(input clk, input readEn, input [3:0] readAddr, output [7:0] readData);
reg [7:0] mem[15:0];
reg [3:0] readAddr_reg;
reg readEn_reg;
reg [7:0] readData_reg;
always @(posedge clk) begin
  readEn_reg <= readEn;
  readAddr_reg <= readAddr;
end
always @(posedge clk) begin
  if (readEn_reg)
    readData_reg <= mem[readAddr_reg];
end
assign readData = readData_reg;
endmodule
